        ),
        array(
            'title'    => 'Careers',
            'slug'     => 'careers',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Disclosures',
            'slug'     => 'disclosures',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Financial Assistance',
            'slug'     => 'financial-assistance',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Home Wifi',
            'slug'     => 'home-wifi',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Home',
            'slug'     => 'home',
            'template' => 'template-full-width.php',
