        ),
        array(
            'title'    => 'Support_Page',
            'slug'     => 'support_page',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Support_Page_V2',
            'slug'     => 'support_page_v2',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
        array(
            'title'    => 'Support_Page_V3',
            'slug'     => 'support_page_v3',
            'template' => 'template-full-width.php',
            'content'  => base64_decode('')
        ),
